"""
MKT Original Language Commentary — Revelation ch6-11
98 verses, all missing
Run: python3 scripts/zc-original-revelation-6-11.py

Key Greek issues in this range:
- stephanos vs. diadema (victor's wreath vs. royal crown); toxon (bow, no arrow)
- machaira (short sword of civil war) vs. rhomphaia (long sword of divine judgment)
- chloros (sickly pale/green) for the fourth horse
- despotēs vs. kyrios in 6:10 (absolute ownership vs. covenant-Lord)
- esphragismenous (perfect passive: already-sealed state) for the 144,000
- hypokatō tou thysiastēriou: martyrs under the altar as the base of the sacrifice
- orgē tou arniou: the lamb's wrath — the paradox of sacrificial lamb as judge
- poimanei: the Lamb shepherds — inversion of the shepherd metaphor (Ps 23; Ezek 34)
- apsinthos: wormwood, the bitterness of Jer 9:15
- Abaddon/Apollyon: Job/Proverbs destruction-realm becomes a personal name
- pneuma zōēs ek tou theou: Gen 2:7 resurrection language in 11:11
- chronos ouketi estai: 'no more delay' vs. 'no more time' (ambiguous Dan 12 echo)
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

ORIGINAL = {
  "6": {
    "1": '<p><strong>ēnoixen</strong> (aorist) — the Lamb\'s opening of each seal is a distinct completed act, not a continuous process. The Lamb (<em>arnion</em>) is consistently the grammatical subject of the seal-openings throughout ch6, placing his agency at the center of the judgment sequence. The living creature\'s command "Come!" (<em>erchou</em>) is addressed to the horsemen, not to John — imperative, summoning the next judgment into the historical arena.</p>',
    "2": '<p><strong>stephanos</strong> — a victor\'s laurel wreath (as in athletic contests), not <em>diadema</em> (the royal crown worn by sovereigns). The distinction matters: the white rider\'s crown is a conqueror\'s prize, earned in battle, not sovereign authority by nature. <strong>toxon</strong> (bow) — no arrow is mentioned; the bow without an arrow may signal the threat of conquest without its immediate execution. <strong>nikōn kai hina nikēsē</strong> — a present participle ("conquering") followed by an aorist purpose-clause ("in order that he might conquer"): ongoing conquest aimed at total victory.</p>',
    "3": '<p>The seal-opening formula repeats six times in ch6 with minor variations (<em>hote ēnoixen</em>, "when he opened"). The formulaic repetition creates a judicial rhythm: the Lamb presides, the living creatures summon, the rider executes. The repetition is itself a rhetorical signal of divine control over the sequence — history unfolds in measured acts, not chaos.</p>',
    "4": '<p><strong>pyrros</strong> (fiery red) — the color of blood and fire; Zech 1:8 has a red horse among the patrol horses. <strong>machaira</strong> — the short sword associated with assassination and civil violence, as opposed to <em>rhomphaia</em> (the large sword of sovereign/divine judgment in Rev 1:16; 2:12). The distinction: the second rider wields the instrument of internal strife and murder, not conquest in formal warfare. <strong>sphaxōsin</strong> (slay one another) — the reflexive-intensive use: mutual slaughter, not external invasion.</p>',
    "5": '<p><strong>zygos</strong> (pair of scales) — the measurement instrument for rationing; the black horse rider measures out grain, signaling not absolute famine but severe scarcity. Black (<em>melas</em>) in Lam 5:10 is the color of skin blackened by famine. The scales activate the economic register of the judgment: controlled distribution under crisis conditions.</p>',
    "6": '<p><strong>choinix sitou dēnariou</strong> — a <em>choinix</em> of wheat (roughly 1 liter, a day\'s ration for one person) costs a <em>dēnarion</em> (a day\'s wage, Matt 20:2). Normal prices in antiquity were 8-12 <em>choinikes</em> per <em>dēnarion</em>, so this represents roughly an 8-12x price increase — severe inflation but not total starvation. <strong>mē adikēsēs</strong> (do not harm — aorist subjunctive of prohibition) — the oil and wine (luxury goods) are exempted, suggesting the judgment falls hardest on those dependent on grain (the poor) while the wealthy continue relatively unaffected.</p>',
    "7": '<p>The fourth seal formula is identical to the second and third. John carefully maintains the structural symmetry: the progression from white (conquest) → red (civil war) → black (famine) → pale (death) traces an escalating logic of historical judgment.</p>',
    "8": '<p><strong>chloros</strong> — literally green, the sickly pale color of disease and decay; the only use of <em>chloros</em> for a horse; elsewhere it describes vegetation (grass, 8:7; 9:4). The pallor of a corpse. <strong>Thanatos</strong> (Death personified) and <strong>Hadēs</strong> (the underworld realm) are paired — Death kills, Hades receives. <strong>rhomphaia</strong>, <strong>limos</strong>, <strong>thanatos</strong>, <strong>thēria</strong> (sword, famine, pestilence/death, wild beasts) — the four agents echo Ezek 14:21 exactly (YHWH\'s four severe judgments on Jerusalem: sword, famine, wild beasts, plague). John alludes to the Ezekiel formula with one substitution.</p>',
    "9": '<p><strong>hypokatō tou thysiastēriou</strong> — "under the altar." In the Mosaic sacrificial system, the blood of the burnt offering was poured at the base (<em>hypo</em>) of the altar (Lev 4:7, 18). The martyrs are positioned as sacrificial blood — their deaths are the ultimate offering, their location at the altar\'s base making them liturgically present as sacrifices. <strong>hesphasmenōn</strong> (perfect passive participle of <em>sphazō</em> — slaughtered/killed; the same verb as "the Lamb as though slaughtered" in 5:6) — the martyrs share the vocabulary of the Lamb\'s own death.</p>',
    "10": '<p><strong>despota</strong> — not <em>Kyrie</em> (covenant-Lord) but <em>despotēs</em> (absolute owner/master), used elsewhere for God in Lk 2:29; Acts 4:24; 2 Pet 2:1; Jude 4. The title of absolute sovereignty is invoked specifically in the context of the prayer for justice — the martyr-souls appeal to the one who owns them completely. <strong>ekdikeis</strong> (present tense: do you judge and avenge?) — an impatient present, not a future hope: "are you not judging?" <strong>tous katoikountas epi tēs gēs</strong> — "those who dwell on the earth" becomes Revelation\'s technical phrase for the world-system opposed to God (used 11 more times).</p>',
    "11": '<p><strong>stolē leukē</strong> — a white robe (<em>stolē</em>, the long robe worn by priests and dignitaries; cf. 7:9,13,14). The gift of the robe signals vindication and priestly dignity. <strong>plērōthōsin</strong> (aorist passive subjunctive of <em>plēroō</em>) — "until the number might be completed/fulfilled." The martyrs\' death-quota must be filled; this is not passive resignation but the framework that interprets ongoing persecution as purposive, not random. The present tense of the martyrdom-mandate ("those about to be killed") implies ongoing persecution at the time of writing.</p>',
    "12": '<p><strong>seismos megas</strong> (great earthquake) — seismic language for divine theophany runs from Exod 19:18 through Isa 29:6 and Joel 2:10 into Revelation\'s judgment vocabulary. <strong>sakkos trichinos</strong> (sackcloth made of hair) — the mourning garment; the blackening of the sun in mourning-cloth recalls Isa 50:3 ("I clothe the sky with darkness and make sackcloth its covering"). The cosmic signs of vv12-14 draw on the OT "Day of YHWH" tradition.</p>',
    "13": '<p><strong>hōs sykē ballei</strong> (as a fig tree drops) — the fig tree\'s unripe winter fruit (<em>olynthous</em>, the late-hanging figs that fall in a winter gale) is the specific image. This precise detail (unripe figs falling off-season in a storm) is from Isa 34:4 (the fall of Edom\'s host of heaven). The Greek of Revelation reproduces the Isaianic imagery with unusual botanical specificity.</p>',
    "14": '<p><strong>apechōristhē hōs biblion helissomenon</strong> — the sky split apart like a scroll being rolled up; Isa 34:4 again: "the sky will be rolled up like a scroll." <em>Helissomenon</em> (present passive participle — being rolled up, in process) gives the visual of a scroll being wound shut at both ends. <strong>ekinēthēsan</strong> (aorist passive) — every mountain and island was moved from its place; the world-map is being disassembled.</p>',
    "15": '<p>The sevenfold list of humanity (kings, great ones, generals, rich, powerful, every slave, every free person) is a merism for all of human social hierarchy — from top to bottom, no one is exempt. The syntax places the powerful first and the powerless last, then collapses the distinction: "every slave and every free person" — the great leveling of the Day of Judgment.</p>',
    "16": '<p><strong>orgē tou arniou</strong> — "the wrath of the Lamb" — the most theologically paradoxical phrase in Revelation. The Lamb (<em>arnion</em>: diminutive, a small lamb) is the symbol of innocent meekness and sacrificial death; yet his <em>orgē</em> (wrath) is the most terrifying prospect facing the world-system\'s inhabitants. The phrase is unique; nowhere else in the NT is divine wrath attributed specifically to Christ as the Lamb.</p>',
    "17": '<p><strong>ēlthen</strong> (aorist: has come, arrived) — not "is coming" but "has arrived." The great day of wrath is treated as already present, not still future. <strong>tis dynatai stathēnai</strong> — "who is able to stand?" — an OT formula for surviving divine judgment (Ps 76:7; Mal 3:2: "who can endure the day of his coming? who can stand when he appears?"). The rhetorical question anticipates ch7\'s answer: the sealed servants of God.</p>'
  },
  "7": {
    "1": '<p><strong>tessaras anemous</strong> — the four winds from the four corners; Zech 6:5 (the four spirits/winds of heaven) and Dan 7:2 (the four winds stirring up the sea from which the beasts arise). The holding back of the four winds is a temporary restraint on cosmic judgment — the angels hold history in suspension before the sealing.</p>',
    "2": '<p><strong>sphragida Theou zōntos</strong> — the seal of the living God. <em>Sphragis</em> (seal/signet) marks ownership and guarantees authenticity; in Ezek 9:4, YHWH marks the foreheads of those who mourn over Jerusalem before the destroying angels go through. Rev 7 is the eschatological counterpart: God\'s own mark of ownership protects from the coming judgment. <strong>anatolē hēliou</strong> (rising of the sun, the east) — the direction associated with the returning glory of God (Ezek 43:2; 44:1-2).</p>',
    "3": '<p><strong>sphragisōmen</strong> (aorist subjunctive: until we might seal) — the sealing is a punctiliar act to be completed before harm is permitted. The aorist subjunctive of purpose in a temporal clause stresses the completion of the sealing before the wind-release. <strong>epi tōn metōpōn autōn</strong> — on their foreheads — Exod 13:9 places the Passover sign as a reminder "on your forehead"; Rev places the ownership-seal on the same location, linking Passover protection with the new-Exodus sealing.</p>',
    "4": '<p><strong>hekaton tesserakonta tessares chiliades</strong> (144,000) — the number is 12 × 12 × 1,000: the arithmetic of symbolic completeness. Twelve is the number of the tribes of Israel (the covenant people); twelve squared (the people in their fullness) multiplied by a thousand (the number of divine abundance). The tribal list that follows (vv5-8) deviates from standard OT lists in significant ways — Judah is first (not Reuben the firstborn); Dan is omitted; Manasseh replaces it — suggesting symbolic rather than literal enumeration.</p>',
    "5": '<p>Judah is listed first (not Reuben, the firstborn), because the Lamb who opens the seals is from Judah (5:5). The tribal list is reordered around the Lion of Judah: the tribe that produced the Messiah heads the eschatological register. The twelve-thousand-per-tribe structure is perfectly uniform — no tribe has more or fewer — signaling an idealized, symbolic completeness.</p>',
    "6": '<p>The tribal enumeration (vv5-8) proceeds through the list with mechanical regularity. Dan is absent and Manasseh is added (both son and father of Joseph appear). Early patristic tradition suggested Dan was omitted because Antichrist would come from Dan (Gen 49:17 — "Dan will be a serpent by the roadside"); whether that is the author\'s intent is uncertain. The completeness of twelve tribes is maintained by the substitution.</p>',
    "7": '<p>Simeon and Levi — the violent brothers of Gen 34 who were scattered (Gen 49:5-7) — appear in the sealing list. Jacob\'s curse on them is not the final word: the eschatological community includes even those whose ancestors were under judgment. The tribal list is redemptive rather than merely genealogical.</p>',
    "8": '<p>The list closes with Benjamin. The twelve tribes together constitute the new Israel — not a literal census but a symbolic statement of the complete covenantal community that will survive the judgment. The sealing answers the question of v17 ("who is able to stand?"): those on whom God\'s own seal has been placed.</p>',
    "9": '<p><strong>ochlus polys hon arithmēsai auton oudeis ēdynato</strong> — "a great multitude which no one was able to count." This directly contrasts with the 144,000 who were precisely numbered; the two visions are likely the same community seen from different angles — the finite covenant-structure (144,000) and the infinite eschatological reality (innumerable multitude). <strong>stolas leukas</strong> (white robes) and <strong>phoinikes</strong> (palm branches) — the palm branches recall the Feast of Booths (Lev 23:40; Neh 8:15) and the triumphal entry (John 12:13), both moments of covenant celebration.</p>',
    "10": '<p><strong>hē sōtēria tō Theō hēmōn</strong> — "salvation belongs to our God." The dative of possession: salvation is not a human achievement but the property of God, who loans it to his people. The parallel "and to the Lamb" makes salvation jointly attributed to God and the Lamb — the same co-attribution seen throughout the doxologies of Revelation (cf. 5:13).</p>',
    "11": '<p><strong>epesan epi ta prosōpa autōn</strong> (fell on their faces) — the standard LXX gesture of prostration before the divine Presence (Ezek 1:28; 3:23; 43:3; 44:4). In Revelation, the twenty-four elders fall prostrate repeatedly (4:10; 5:8,14; 7:11; 11:16; 19:4). The accumulated weight of repetition establishes the posture of creation before the Creator as the fundamental mode of heavenly existence.</p>',
    "12": '<p>The sevenfold doxology (<em>eulogia, doxa, sophia, eucharistia, timē, dynamis, ischys</em>: blessing, glory, wisdom, thanksgiving, honor, power, might) is framed by matching <em>Amēn</em>. The seven attributes in doxological form recall the throne-room hymns of chs 4-5. The addition of <em>eucharistia</em> (thanksgiving) to the list distinguishes this doxology — the redeemed multitude adds gratitude to the creation\'s praise.</p>',
    "13": '<p><strong>apokritheis ... eipen</strong> — one of the elders takes the role of interpretive guide, addressing John with a rhetorical question designed to draw out the answer the elder will then supply. This Socratic pedagogical technique (the leader asks, the pupil professes ignorance, the leader explains) is found in apocalyptic literature (Dan 7:16; 4 Ezra 4:52-5:13). John\'s "Sir, you know" (<em>Kyrie mou, sy oidas</em>) is the appropriate deferential response.</p>',
    "14": '<p><strong>hoi erchomenoi ek tēs thlipseōs tēs megalēs</strong> — "those coming out of the great tribulation" — present participle: they are in the process of emerging, not yet finished. <strong>eplynan tas stolas autōn</strong> (aorist: they washed their robes) and <strong>eleukanan</strong> (aorist: made them white) — both completed acts. The paradox: made white in blood. <em>Haimati</em> (blood, dative of means/instrument) — the blood of the Lamb is the cleansing agent that reverses the normal function of blood (which stains). The syntax forces the paradox: "they made them white in blood."</p>',
    "15": '<p><strong>latreuousin autō hēmeras kai nyktos</strong> — "they serve him day and night" — the eschatological reversal of the present situation (where God\'s servants are persecuted and killed). <em>Latreuō</em> is the technical term for priestly/liturgical service (Heb 9:9; 10:2; 13:10). The redeemed serve as priests in the heavenly temple. <strong>skēnōsei ep\' autous</strong> — "will spread his tent over them" (future); the verb <em>skēnoō</em> echoes both the wilderness Tabernacle and John 1:14 (the Word tabernacled among us); here it is the permanent eschatological dwelling.</p>',
    "16": '<p><strong>ou peinasousin eti oude dipsēsousin eti</strong> — future tenses (both negated by <em>eti</em>, "any longer/still") describing permanent reversal. The "no longer" structure signals that the present experience is hunger and thirst — these are martyrs who suffered real deprivation. The promise reverses their specific earthly experience. <strong>ou mē pesē ep\' autous ho hēlios</strong> — Isa 49:10 ("they will not hunger or thirst; neither the scorching wind nor the sun will beat on them") is quoted almost verbatim; the servant\'s promise is fulfilled in the great multitude.</p>',
    "17": '<p><strong>to arnion ... poimanei autous</strong> — the Lamb will shepherd them (future <em>poimainō</em>). The word for shepherd the flock is applied to the Lamb — the most compressed theological paradox in the chapter: the sacrificed animal is the shepherd. Behind this stands Ezek 34:23 (David my servant will shepherd them) and Ps 23 (YHWH my shepherd). <strong>zōēs</strong> (of life) modifying "springs" (not "rivers of life" but <em>pēgas hydatōn zōēs</em>, springs of living water) — echoes Jer 2:13 (YHWH as the spring of living water) and John 4:14; 7:38. <strong>exaleipsei ... pan dakryon</strong> (will wipe away every tear) — Isa 25:8; the eschatological comfort of YHWH personally wiping tears.</p>'
  },
  "8": {
    "1": '<p><strong>sigē en tō ouranō hōs hēmimōrion</strong> — "silence in heaven for about half an hour." The silence is without precedent in Revelation\'s preceding heavenly scenes, which have been filled with the voices of living creatures, elders, and myriads of angels. The silence is liturgical — it parallels the practice of silence before solemn pronouncements in Jewish and later Christian worship (Hab 2:20: "YHWH is in his holy temple; let all the earth be silent before him"; Zeph 1:7; Zech 2:13). The "half an hour" is one of Revelation\'s rare time-specifications, marking the solemnity of what follows.</p>',
    "2": '<p><strong>hoi hepta angeloi hoi enōpion tou Theou</strong> — "the seven angels who stand before God." These are the archangels of Jewish tradition (1 Enoch 20:1-8 names Uriel, Raphael, Raguel, Michael, Saraqael, Gabriel, and Remiel as the seven holy angels "who present the prayers of the saints and enter into the presence of the glory of the Holy One"). The trumpets given to them are judicial instruments — in OT warfare the trumpets were blown before battle (Num 10:9; Josh 6:4-5).</p>',
    "3": '<p><strong>libano pollo</strong> — "a large amount of incense." The incense altar before the throne corresponds to the golden altar of incense in the Tabernacle and Temple, positioned before the Holy of Holies. <strong>tais proseuchais tōn hagiōn pantōn</strong> — "with the prayers of all the saints." The incense is not merely liturgical decoration but is given to be offered "with" the prayers — the angels\' offering amplifies and presents the accumulated prayers of God\'s people. The grammar makes the incense and prayers co-offerings before God.</p>',
    "4": '<p><strong>anebē ho kapnos tōn thymiamatōn</strong> — "the smoke of the incense went up" — the direction is key: prayers ascend to God. The prayers of the saints have been accumulating (cf. 6:9-11: the martyr-souls crying out, "how long?"); now they ascend as incense, setting in motion the judgment-sequence of the trumpets. The passive structure signals divine reception: God receives the prayers and acts in response.</p>',
    "5": '<p><strong>eilēphen ton libanōton kai egemisen auton ek tou pyros tou thysiastēriou</strong> — the same censer that held the incense-with-prayers is now filled with fire from the altar and hurled down. The movement is exact: prayers ascend, judgment-fire descends. <strong>brontai kai phōnai kai astrapai kai seismos</strong> (thunder, rumblings, lightning, earthquake) — the Sinai theophany-formula (Exod 19:16-18), which recurs at each of Revelation\'s great climaxes (11:19; 16:18).</p>',
    "6": '<p>The seven angels prepare (<em>ētoimasan</em>, aorist: completed preparation) to sound. The verb is not "picked up" but "prepared" — a deliberate act of readiness before execution. The symmetry with ch7 (sealing before trumpets) is structural: the servants of God are sealed before the judgment-trumpets sound, ensuring the protection of 7:3 is in place.</p>',
    "7": '<p><strong>chalaza kai pyr memigmena en haimati</strong> — "hail and fire mixed with blood." The hail recalls Exod 9:22-26 (seventh Egyptian plague); the fire recalls Joel 2:30 ("I will show wonders in the heavens and on the earth: blood and fire and columns of smoke"); the blood adds a third element absent from Exod 9. The mixture creates a compound plague-sign that draws on multiple OT registers simultaneously. <strong>to triton</strong> (a third) — the partial judgment (one-third affected) distinguishes the trumpets from the bowls (total judgment); the scale is warning-not-yet-final.</p>',
    "8": '<p><strong>hōs oros mega pyrī kaiomenon</strong> — "something like a great mountain blazing with fire was thrown into the sea." The simile-hedge (<em>hōs</em>, like) is typical of John\'s visionary caution: he does not claim to describe the thing itself but its appearance. The blazing mountain recalls Jer 51:25 ("Behold I am against you, O destroying mountain... I will make you a burned-out mountain"). <strong>egeneto eis haima</strong> — became blood (not "turned blood-red" but ontological transformation, as in the Exodus plague).</p>',
    "9": '<p><strong>ta echonta psychas</strong> (those having souls/lives) — the phrase emphasizes that these are living creatures, not merely organisms; the destruction is of ensouled life, not just biological matter. <strong>diephtharesan</strong> (aorist passive: were destroyed/corrupted) — the same root as <em>phtheirō</em> (to corrupt, destroy) used for the corruption of the false teachers throughout the epistles. The judgment-vocabulary links the moral and the cosmic.</p>',
    "10": '<p><strong>astēr megas kaiomenos hōs lampas</strong> — "a great star blazing like a torch." The torch-simile (<em>lampas</em>, not <em>lychnia</em>) suggests brilliant, streaming fire rather than a contained flame. <strong>epesan ek tou ouranou</strong> — "fell from heaven" (aorist); the falling star echoes Isa 14:12 ("How you have fallen from heaven, morning star, son of the dawn") and Luke 10:18 ("I saw Satan fall like lightning from heaven"). The connection to fallen angelic power is interpretively possible but not made explicit by the text.</p>',
    "11": '<p><strong>Apsinthos</strong> — wormwood (<em>Artemisia absinthium</em>), an extremely bitter plant; in the OT, wormwood (<em>la\'anah</em>) symbolizes divine judgment through bitter experience (Jer 9:15: "I will feed this people with wormwood and give them bitter water to drink"; Lam 3:15,19; Prov 5:4). The name "Wormwood" given to the star is not found in the OT; John creates the designation to match the effect. <strong>eplēthysan</strong> (aorist passive: were made bitter) — the waters become their punishment.</p>',
    "12": '<p><strong>eplēgē to triton tou hēliou</strong> — "a third of the sun was struck." The passive <em>eplēgē</em> (was struck) uses divine-passive construction; the agent is unstated. The "third" (triton) motif runs through the trumpet sequence — partial rather than total disruption, distinguishing the trumpets from the final bowl-judgments. The darkening of sun, moon, and stars recalls the Egyptian darkness-plague (Exod 10:21) and Joel 2:10 and Amos 8:9 ("I will make the sun go down at noon").</p>',
    "13": '<p><strong>aetos petomenon en mesouranēmati</strong> — "an eagle flying in midheaven." The eagle as a prophetic messenger recalls Deut 28:49 (the eagle as judgment from afar) and Hos 8:1 ("an eagle over the house of the LORD"). <strong>ouai ouai ouai</strong> — the triple woe, corresponding to the three remaining trumpets. The triplication of the woe-formula is intensification by repetition, a Hebraic rhetorical device. The transition at v13 divides the seven trumpets into two groups: 1-4 (cosmic) and 5-7 (demonic/historical), with the woe-eagle marking the break.</p>'
  },
  "9": {
    "1": '<p><strong>astēra ek tou ouranou peptōkota eis tēn gēn</strong> — "a star that had fallen from heaven to earth." The perfect participle <em>peptōkota</em> (already fallen, in a state of having fallen) distinguishes this from the falling of 8:10 (aorist, the moment of falling). This star is already in its fallen state before John sees it — a being of previously higher status now consigned to the lower realm. The key to the shaft of the Abyss is given to him: the fallen one is granted authority over the prison-realm, not as a possession but as a temporary grant.</p>',
    "2": '<p><strong>ho phreatos tēs abyssou</strong> — "the shaft of the Abyss" (literally: the well/pit of the bottomless pit). <em>Abyssos</em> in LXX translates <em>tehōm</em>, the primordial deep of Gen 1:2 — the undifferentiated chaos before creation. In Jewish apocalyptic it becomes the prison of rebellious spirits (1 Enoch 18:11-16; Jude 6: "chains of darkness"). The smoke rising from the opened Abyss darkens the sun — the opened chaos-realm corrupts the created order from below.</p>',
    "3": '<p><strong>akrides</strong> (locusts) — in the OT, the locust-plague is a recurring image of divine judgment (Exod 10:12-15; Joel 1-2; Amos 7:1). Joel 1:6 describes the locust-army with lion\'s teeth, and Joel 2:4-5 describes them as horses rushing into battle — language John will reprise in vv7-9. The scorpion-power grants them the ability to inflict pain without killing — a new capacity beyond the historical locust\'s grain-destruction.</p>',
    "4": '<p><strong>mē adikēsōsin</strong> — "they were commanded not to harm" (aorist subjunctive of prohibition). The specific exclusions (grass, green plants, trees) invert the normal locust pattern — the historical locusts destroy vegetation, these locusts target only unprotected people. The inversion signals that this is not literal entomology but a symbolic description of a spiritual/historical force. <strong>sphragida tou Theou</strong> (the seal of God) — the protection established in ch7 holds: those sealed by God are exempt from the Abyss-locusts.</p>',
    "5": '<p><strong>basanismos ... hōs basanismos skorpiou</strong> — "torment ... like the torment of a scorpion." The scorpion sting produces intense pain but rarely death; the five months of torment without death is a judgment of prolonged suffering. <strong>mēnas pente</strong> (five months) — the natural lifespan of a locust (May to September, approximately five months); the duration is calibrated to the creature\'s biology but the function is symbolic.</p>',
    "6": '<p><strong>zētēsousin ... thanaton kai ou mē heurōsin</strong> — "they will seek death and will by no means find it" (ou mē + future is the strongest Greek negation). The reversal of death\'s availability — normally an ever-present option — is itself a form of judgment. Compare Job 3:21 (those who long for death that does not come) and Jer 8:3 (death preferred to life). The inability to die transforms what might be merciful release into perpetual torment.</p>',
    "7": '<p><strong>hōs hippoi hētoimasmenoi eis polemon</strong> — "like horses prepared for battle." The extended locust-description in vv7-10 is a series of simile-stacks (<em>hōs</em>, like): crowns like gold, faces like humans, hair like women\'s, teeth like lions\'. John accumulates similes to describe what cannot be directly named — a composite creature from the Abyss that defies normal taxonomic categories. The horse-armor (Joel 2:4-5) is the base, elaborated beyond anything in the OT source.</p>',
    "8": '<p><strong>trichas hōs trichas gynaikōn</strong> — "hair like women\'s hair." This detail is not in Joel\'s locust-army; it is John\'s addition. The significance is debated: some suggest the long, flowing mane of horses; others see it as an additional element of the uncanny, making the locust-creatures both masculine (battle-ready) and feminine (long hair) — a gender-crossing that signals their category-transgressing nature from the Abyss. <strong>odonas hōs leontos</strong> — Joel 1:6 explicitly gives the locust "teeth of a lion."</p>',
    "9": '<p><strong>phōnē tōn pterygōn autōn hōs phōnē harmatōn hippōn pollōn trechontōn eis polemon</strong> — "the sound of their wings was like the sound of chariots, of many horses rushing into battle." Joel 2:5 ("like the noise of chariots they leap over the mountaintops, like the crackling of fire consuming stubble, like a powerful army drawn up for battle"). John\'s auditory simile draws directly from Joel\'s battle-army of locusts, but the addition of chariot-noise multiplies the scale.</p>',
    "10": '<p><strong>hai ourai autōn homoiai skorpiois</strong> — "their tails were like scorpions." The double-ended threat (mouths that wound, tails that sting) makes the creature dangerous in all directions. <strong>to adikēsai tous anthrōpous mēnas pente</strong> — "to harm people for five months": the same duration restated, now attributed specifically to the tails. The repetition of the five-month limit emphasizes the constraint placed on even demonic power — judgment operates within defined limits.</p>',
    "11": '<p><strong>Abaddōn ... Apollyōn</strong> — the Hebrew name given first (Abaddon, from <em>abad</em> = to perish/be destroyed; appearing in Job 26:6; 28:22; 31:12; Ps 88:11; Prov 15:11 as the realm of destruction beneath Sheol), then the Greek equivalent (Apollyon, the Destroyer). The naming of the king of the Abyss with this word gives a personal identity to the realm of destruction — Abaddon is no longer just a place but a person/power. The Greek name <em>Apollyōn</em> also phonetically evokes <em>Apollo</em>, the Greek sun-god whose symbol was the locust; some scholars read an anti-imperial polemic against the Neronian or Domitian cult here.</p>',
    "12": '<p><strong>hē ouai hē mia apēlthen</strong> — "the first woe has passed" — the perfect tense of departure (<em>apēlthen</em>, aorist actually, indicating completed departure). The structural marker divides the trumpet sequence and prepares for the sixth trumpet\'s even greater judgment. The announcement that "two more woes are still coming" creates narrative tension and eschatological urgency.</p>',
    "13": '<p><strong>phōnēn mian ek tōn tessarōn keratōn tou thysiast ēriou tou chrysou</strong> — "a voice from the four horns of the golden altar." The horns of the altar were the points to which the blood of the sin offering was applied (Lev 4:7,18,25,30; Exod 29:12); they were also grasped by those seeking sanctuary (1 Kgs 1:50-51; 2:28). The voice from the altar-horns links the judgment of the sixth trumpet to the altar-prayers of 8:3-5 and the martyr-souls of 6:9-10: justice proceeds from the place of sacrifice and prayer.</p>',
    "14": '<p><strong>luson tous tessaras angelous tous dedemenous epi tō potamō tō megalō Euphratē</strong> — "release the four angels bound at the great river Euphrates." The Euphrates is the eastern boundary of the promised land (Gen 15:18) and the symbolic boundary between the covenant people and the threatening empires of Assyria and Babylon. The four bound angels (bound = <em>dedemenous</em>, perfect passive participle, in a lasting state of restraint) are released at the specific moment designated — the precise timing of v15.</p>',
    "15": '<p><strong>hoi hētoimasmenoi eis tēn hōran kai hēmeran kai mēna kai eniauton</strong> — "prepared for the hour, day, month, and year." The fourfold time-specification (hour, day, month, year) indicates absolute divine precision: this judgment was ordained for this exact moment in the cosmic calendar. <em>Hētoimasmenoi</em> (perfect passive participle: having been prepared) — the preparation was completed in the past; the angels have been waiting in their bound state for this moment to arrive.</p>',
    "16": '<p><strong>dyo myriades myriadōn</strong> — "two myriads of myriads" = 200,000,000 (two hundred million). <em>Myrias</em> is ten thousand, the largest numeral in Greek; <em>myriad of myriads</em> is the limit of numerical expression. The army is beyond counting-in-practice, echoing the innumerable host of 5:11 but now for judgment rather than worship. <strong>ēkousa ton arithmon autōn</strong> — "I heard their number" (not counted it) — John receives the numerical revelation aurally.</p>',
    "17": '<p><strong>houtōs eidon tous hippous en tē horasei kai tous kathēmenous ep\' autōn</strong> — "this is how I saw the horses in my vision." The vision-qualifier (<em>en tē horasei</em>, in the vision) maintains the visionary frame around the description. <strong>purinos kai hyakinthinos kai theiōdeis</strong> — fire-colored, dark blue (<em>hyakinthinos</em>, the color of the hyacinth flower, or possibly smoke-dark), and sulfur-yellow: the three colors of fire, smoke, and sulfur that are named in v18 as the three plagues. The horses\' appearance pre-figures the judgment they carry.</p>',
    "18": '<p><strong>ek tōn triōn plēgōn toutōn apektanthē to triton tōn anthrōpōn</strong> — "by these three plagues a third of humanity was killed." The three plagues (fire, smoke, sulfur — <em>pyr, kapnos, theion</em>) are also the substances associated with the destruction of Sodom (Gen 19:24,28: fire and sulfur; smoke rising like smoke from a furnace). The echo of Sodom at the cosmic scale is deliberate: the sixth-trumpet judgment is Sodom writ large.</p>',
    "19": '<p><strong>hē gar exousia tōn hippōn en tō stomati autōn estin kai en tais ourais autōn</strong> — "the power of the horses is in their mouths and in their tails." The serpent-tails recall the Eden serpent and anticipate the serpent-dragon of ch12. The power of the horse-cavalry is both offensive (mouths) and dangerous from behind (tails) — a military formation impossible in normal warfare, signaling the supernatural character of this judgment-force.</p>',
    "20": '<p><strong>ou metenoēsan</strong> — "they did not repent" (aorist negated). The purpose of the plagues is repentance; the repeated failure to repent (<em>metanoeō</em> appears in vv20-21 twice, and in 16:9,11) is the defining response of "those who dwell on the earth" (the world-system) to divine judgment. <strong>ta erga tōn cheirōn autōn</strong> (the works of their hands) — the idols; Ps 115:4-7 and 135:15-17 describe idols as "the work of human hands" that cannot see, hear, or walk — the same three disabilities listed here.</p>',
    "21": '<p><strong>phonōn ... pharmakōn ... porneias ... klemmaton</strong> — murders, sorceries, sexual immorality, thefts. <em>Pharmakōn</em> (sorceries) is from <em>pharmakon</em> (drug/poison/charm) — the word that gives English "pharmacy"; in the NT it consistently refers to occult practices that involve substances, spells, or enchantments (Gal 5:20; Rev 18:23; 21:8; 22:15). The fourfold list is a compressed moral inventory of the world-system\'s characteristic sins.</p>'
  },
  "10": {
    "1": '<p><strong>angelon ischuron katabainonta ek tou ouranou</strong> — "a mighty angel coming down from heaven." This angel is distinct from the seven trumpet-angels; his appearance (cloud-wrapped, rainbow crown, sun-face, fire-pillar legs) is theophanic — resembling the divine appearances of ch4 and Ezek 1. <strong>iris epi tēs kephalēs</strong> — "a rainbow above his head." The rainbow (<em>iris</em>) appears in Ezek 1:28 as the sign of the divine glory (the appearance of the likeness of the glory of the LORD was like a rainbow in a cloud on a rainy day). The angel\'s rainbow-crown connects him to the covenant-faithfulness symbolized by the rainbow since Gen 9:13.</p>',
    "2": '<p><strong>biblaridion ēneōgmenon</strong> — "a little scroll lying open." The diminutive <em>biblaridion</em> (little scroll) distinguishes it from the great sealed scroll of ch5 (<em>biblion</em>). This scroll is already open — the contents are accessible. John will eat it in v9-10. The small open scroll stands in contrast to the sealed closed scroll of ch5: a specific, limited prophetic commission rather than the entire cosmic plan.</p>',
    "3": '<p><strong>hōsper leōn mykatai</strong> — "like a lion roaring" (<em>mykaomai</em>, the bellow of a lion or bull). The lion\'s roar as a divine-speech metaphor appears in Hos 11:10 and Joel 3:16 ("YHWH roars from Zion"). The seven thunders speak — the number seven signals completeness; John is about to record their speech when he is commanded to seal it.</p>',
    "4": '<p><strong>sphragison ha elalēsan hoi hepta brontai kai mē auta grapsēs</strong> — "seal up what the seven thunders said and do not write it." The command to seal recalls Dan 8:26 ("seal up the vision, for it is for many days") and Dan 12:4,9 ("close up and seal the words of the scroll until the time of the end"). This is the only content in Revelation that is explicitly withheld from the reader — a deliberate gap in the revelation that resists the apocalyptic reader\'s desire for complete knowledge. Contrast Rev 22:10 ("Do not seal up the words of the prophecy of this scroll, because the time is near").</p>',
    "5": '<p><strong>ton dexion cheira autou eis ton ouranon</strong> — "raised his right hand toward heaven." The oath-gesture: lifting the right hand toward heaven in the swearing of an oath (Deut 32:40; Dan 12:7: "the man dressed in linen raised his right hand and his left hand toward heaven and swore by him who lives forever"). The angel\'s swearing by the living God (v6) is a direct allusion to Dan 12:7.</p>',
    "6": '<p><strong>chronos ouketi estai</strong> — "there will be no more delay" (or: "time will be no more"). The Greek is ambiguous: <em>chronos</em> can mean "delay" (as in "no more waiting") or "time" (as in eschatological time ending). Most interpreters favor "delay" given the context of the imminent seventh trumpet and the completion of the mystery. <strong>hos ektisen ton ouranon ... gēn ... thalassan</strong> — the oath is sworn by the Creator of heaven, earth, and sea (the tripartite creation formula from Gen 1, repeated in the Decalogue: Exod 20:11).</p>',
    "7": '<p><strong>etelesthē to mystērion tou Theou</strong> — "the mystery of God will be fulfilled." <em>Mystērion</em> in Paul refers to the previously hidden divine plan now revealed in Christ (Rom 16:25; Eph 1:9; 3:3-9; Col 1:26-27). Here, the mystery is the complete plan of salvation-through-judgment that the prophets announced but only partially saw. <em>Euēngelisen</em> (announced the good news) — the mystery was previewed as <em>euangelion</em> (gospel): even the judgment-plan is good news in Revelation\'s theodicy.</p>',
    "8": '<p><strong>hypage labein to biblaridion</strong> — "go take the little scroll." John is commanded to take active possession: not to receive passively but to approach and take. The two-part transaction (request and grant, vv8-9) before the eating foreshadows the bitter-sweet experience — the prophet must want and accept the prophetic commission before experiencing its weight.</p>',
    "9": '<p><strong>pikranei sou tēn koilian alla en tō stomati sou estai glykу hōs meli</strong> — "it will make your stomach bitter, but in your mouth it will be as sweet as honey." Ezek 2:8-3:3: Ezekiel ate a scroll and it was sweet as honey — but Ezekiel was then sent to speak hard words to a rebellious people. The bitterness-after-sweetness in John\'s commissioning adds the experiential weight that Ezekiel\'s version lacked: the prophetic word is genuinely sweet to receive (it is God\'s word) and genuinely bitter to carry (its content is judgment).</p>',
    "10": '<p><strong>ēn glykу hōs meli ... epikranthē hē koilia mou</strong> — "it was sweet as honey... my stomach was made bitter" (aorist passive). The aorist <em>epikranthē</em> (was embittered) marks the bitterness as a specific, completed experience. The mouth-to-stomach progression maps the prophetic experience: the initial reception of God\'s word is joyful; the internalization and digestion of its meaning (the full weight of the judgments to come) is painful. The prophet does not remain at a distance from his message.</p>',
    "11": '<p><strong>dei se palin prophēteusai</strong> — "it is necessary for you to prophesy again." <em>Dei</em> (it is necessary/must) is the divine-necessity verb in the NT (used for Christ\'s passion in Lk 24:7; for Paul\'s preaching in Acts 9:6; for apocalyptic events in Rev 1:1; 4:1). John\'s prophetic commission is renewed after the scroll-eating: the re-commissioning mid-vision (like Ezekiel\'s re-commissioning in Ezek 3:4-11) sends him forward with an expanded mandate: "peoples, nations, languages, and kings."</p>'
  },
  "11": {
    "1": '<p><strong>kalamos homoios rhabdō</strong> — "a measuring rod like a staff." The combination of <em>kalamos</em> (reed, the measurement tool) and <em>rhabdos</em> (staff, the shepherd\'s or authority-rod) merges two instruments. Ezek 40:3 uses a measuring rod (of six cubits); Zech 2:1-5 uses a measuring line for Jerusalem. In both prophetic texts, measuring signals divine care and preservation — the measured thing belongs to God. <strong>metron ton naon tou Theou</strong> — "measure the temple of God." The imperative commission: measurement as an act of claiming divine ownership over what is measured.</p>',
    "2": '<p><strong>tēn aulēn tēn exōthen ... ekbale exōthen</strong> — "the court outside... throw it outside." The outer court is excluded from measurement: it is "given to the nations," and they will trample the holy city for <strong>mēnas tesserakonta [kai] dyo</strong> (42 months). The 42-month period (= 3.5 years = 1260 days = "time, times, and half a time" of Dan 7:25; 12:7) is the symbolic half-seven — the incomplete time of the nations\' domination, bounded and limited. <em>Patēsousin</em> (will trample) echoes Lk 21:24 ("Jerusalem will be trampled on by the Gentiles until the times of the Gentiles are fulfilled").</p>',
    "3": '<p><strong>tois dysin martyrsin mou</strong> — "my two witnesses." The "my" (<em>mou</em>) marks them as belonging to the Lord: they are his witnesses, as Christ is the faithful witness (<em>ho martys ho pistos</em>, 1:5). <strong>sakkous</strong> (sackcloth) — the mourning garment of the prophets (Isa 20:2; Zech 13:4) signals that the witnesses prophesy in the mode of lamentation, not triumph. 1260 days of sackcloth-prophecy — the prophetic office in the period of the nations\' trampling is marked by grief.</p>',
    "4": '<p><strong>hai dyo elaiai kai hai dyo lychniai</strong> — "the two olive trees and the two lampstands." Zech 4:3,11,14: the two olive trees flanking the golden lampstand are "the two anointed ones who stand before the Lord of the whole earth" — in Zechariah\'s context, Zerubbabel (civil) and Joshua (priestly). In Revelation the two witnesses together embody both offices. The lampstand connection links them to the seven churches of chs 1-3 (which are lampstands, 1:20): the witnesses are the prophetic-witness function of the church.</p>',
    "5": '<p><strong>pyr ekporeuetai ek tou stomatos autōn</strong> — "fire comes out of their mouths and devours their enemies." The fire-from-mouth is a prophetic power drawn from Elijah (2 Kgs 1:10-12: Elijah calling fire from heaven) and from Jer 5:14 (YHWH\'s words in the prophet\'s mouth as fire that devours). The fire is the fire of the word: the prophetic proclamation that executes judgment. <strong>apoktanthēnai autous</strong> — "must die in this way" (aorist passive infinitive of necessity); the judgment modality is fixed.</p>',
    "6": '<p><strong>kleiein ton ouranon hina mē hyetos brēchē</strong> — "to shut the sky so that no rain falls." Explicitly Elijah\'s power (1 Kgs 17:1; Lk 4:25; Jas 5:17 — Elijah prayed that it would not rain for 3.5 years). <strong>strephousin ta hydata eis haima</strong> — Moses\'s power over water-to-blood (Exod 7:19-20). The two witnesses together embody the Elijah-Moses typology: the two great prophets of Israel whose ministries bracket the OT prophetic tradition. Their pairing at the Transfiguration (Matt 17:3) gives this identification christological precedent.</p>',
    "7": '<p><strong>to thērion to anabainon ek tēs abyssou</strong> — "the beast that rises from the Abyss." This is the beast\'s first appearance in Revelation (it will be developed in chs 13, 17); the brevity here ("the beast") implies the audience already knows the referent, or that this proleptic mention sets up the fuller narrative. <strong>poiēsei meta autōn polemon kai nikēsei autous</strong> — "will make war against them and conquer them and kill them." The beast\'s temporary victory over the witnesses is stated with three aorist future forms (will make, will conquer, will kill) — decisive and brutal.</p>',
    "8": '<p><strong>Sodoma kai Aigyptos</strong> — "Sodom and Egypt." The great city is identified figuratively (<em>pneumatikōs</em>, spiritually/allegorically) with both Sodom (the city of sexual immorality and wickedness, Gen 18-19) and Egypt (the house of slavery, Exod). The identification "where their Lord was crucified" unmistakably identifies the city as Jerusalem — yet its naming as Sodom and Egypt denies it the special status it might claim. Jerusalem has become what it condemned: the city of God\'s witnesses is now the city of anti-God empire.</p>',
    "9": '<p><strong>blepousin to ptōma autōn hēmeras treis kai hēmisy</strong> — "they stare at their bodies for three and a half days." The 3.5-day period mirrors the 3.5-year (42-month/1260-day) ministry period: the same half-seven structure. <strong>ou aphiousin ta ptōmata autōn tethēnai eis mnēma</strong> — "they do not permit their bodies to be placed in a tomb." Refusing burial was the ultimate dishonor in Jewish culture (Deut 28:26; Ps 79:3; Jer 8:2) and in many ancient cultures — the ultimate humiliation of one\'s enemies after death.</p>',
    "10": '<p><strong>euphrainontai ep\' autois kai euphrosunēn poiousin</strong> — "they celebrate and exchange gifts." The gift-exchange (<em>pempousin dōra allēlois</em>) on the occasion of the prophets\' deaths reads like a dark parody of a festival celebration — comparable to the Purim gift-exchange (Esth 9:22: "days of feasting and joy and giving presents to each other"). The world-system celebrates the silencing of the prophetic witness.</p>',
    "11": '<p><strong>pneuma zōēs ek tou Theou eisēlthen en autois</strong> — "the breath/spirit of life from God entered them." The language is deliberately Gen 2:7 (God breathed the <em>nishmat chayyim</em>, the breath of life, into Adam) and Ezek 37:10 (the breath entered the dry bones and they stood on their feet — <em>estēsan epi tous podas autōn</em>). Both OT texts are cited almost verbatim: the resurrection of the witnesses is narrated in the vocabulary of creation and covenant-restoration. <strong>estēsan epi tous podas autōn</strong> — they stood on their feet, the exact phrase of Ezek 37:10.</p>',
    "12": '<p><strong>anabate hōde</strong> — "Come up here!" — the same words spoken to John in 4:1 (his heavenly ascent to see the throne). The witnesses\' ascension in a cloud (<em>en tē nephelē</em>) echoes both the Elijah ascent (2 Kgs 2:11: Elijah taken up in a whirlwind/chariot of fire) and the Christ-ascension (Acts 1:9: "he was taken up before their very eyes, and a cloud hid him from their sight"). <strong>etheōrēsan autous hoi echthroi autōn</strong> — their enemies watched: the public vindication mirrors the public humiliation of their death.</p>',
    "13": '<p><strong>seismos megas egeneto</strong> — "a great earthquake occurred." <em>Seismos</em> (earthquake) in Revelation is always associated with divine judgment and theophanic activity (6:12; 8:5; 11:13,19; 16:18). <strong>to dekaton tēs poleōs epesen</strong> — "a tenth of the city collapsed." The specificity of "a tenth" is unusual in Revelation\'s symbolic arithmetic (normally thirds and quarters); some see it as reflecting the earthquake\'s partial scope — unlike the total judgment of the bowls. <strong>edothē doxa tō Theō tou ouranou</strong> — "they gave glory to the God of heaven" — rare in Revelation (contrast with 16:9,11 where they refuse to repent and give glory); this suggests genuine awe or partial repentance.</p>',
    "14": '<p>The transition marker "the second woe has passed; the third woe is coming soon (<em>tachos</em>)" closes the interlude of the two witnesses and the sixth-trumpet complex. <em>Tachos</em> (quickly/soon) maintains the sense of urgency that runs through the book (1:1; 22:6,7,12,20). The structural function of v14 is bridging: the woe-announcement of 9:12 is fulfilled, and the seventh trumpet (the third woe) is introduced.</p>',
    "15": '<p><strong>egenonto hai basileiai tou kosmou tou Kyriou hēmōn kai tou Christou autou</strong> — "the kingdom of the world has become (aorist: <em>egenonto</em>) the kingdom of our Lord and of his Christ." The aorist marks this as a completed transfer — not "is becoming" but "has become." The seventh trumpet sounds, and heaven announces the fait accompli of the eschatological kingdom. <strong>kai basileusei eis tous aiōnas tōn aiōnōn</strong> — "he will reign forever and ever" (singular: the King, singular, reigns — though "our Lord and his Christ" are two).</p>',
    "16": '<p><strong>epesan epi ta prosōpa autōn kai prosekunēsan tō Theō</strong> — the twenty-four elders prostrate themselves (<em>piptō</em> + <em>prosekunēsan</em>: fall + worship) exactly as in 4:10 and 5:14; the gesture of prostrate worship frames the throne-room scenes. The verb <em>proskuneō</em> in Revelation appears 24 times — the entire book can be read as a contest between whose worship is legitimate.</p>',
    "17": '<p><strong>eilēphas tēn dynamin sou tēn megalēn kai ebasileusas</strong> — "you have taken your great power and have begun to reign." <em>Ebasileusas</em> (aorist: you have begun to reign/you have reigned) — the aorist of divine reign is the announcement of the accomplished fact from the heavenly perspective. <strong>ho ōn kai ho ēn</strong> — "who is and who was." Significantly the third element "who is to come" (<em>ho erchomenos</em>, present in 1:4,8; 4:8) is absent here — because he has now come: the coming is fulfilled.</p>',
    "18": '<p><strong>hōrgisthēsan ta ethnē kai ēlthen hē orgē sou</strong> — "the nations raged and your wrath came." The verb <em>orgizō</em> is applied first to the nations\' rage, then to God\'s wrath — the same root, mirroring each other: the nations\' anger is met by divine anger. The verse condenses Ps 2:1,5 (why do the nations rage... he rebukes them in his wrath) into a single announcement. <strong>tous mikrous kai tous megalous</strong> — "both small and great" — the leveling formula: divine judgment/reward respects no hierarchy.</p>',
    "19": '<p><strong>hē kibōtos tēs diathēkēs autou</strong> — "the ark of his covenant." The ark, which disappeared from the narrative of Israel\'s history after the Babylonian destruction of the Temple (its fate is unknown; 2 Macc 2:4-8 says Jeremiah hid it on Nebo; it was never recovered), is now revealed in the heavenly temple. The unveiling of the heavenly ark at the completion of the seventh trumpet announces the return of the fullness of covenant-presence: what Israel lost is now visible in its eternal, heavenly reality. The Sinai-theophany formula (lightning, thunder, earthquake, hail) frames the revelation as a new Sinai.</p>'
  }
}

def main():
    existing = load_comm('mkt-original', 'revelation')
    merge_comm(existing, ORIGINAL)
    save_comm('mkt-original', 'revelation', existing)

    il = json.loads((ROOT / 'data' / 'interlinear' / 'revelation.json').read_text())
    all_ok = True
    for ch in range(6, 12):
        ck = str(ch)
        il_vv = set(il.get(ck, {}).keys())
        out_vv = set(existing.get(ck, {}).keys())
        missing = sorted(il_vv - out_vv, key=int)
        if missing:
            print(f'  ch{ch}: still missing {missing}')
            all_ok = False
        else:
            print(f'  ch{ch}: complete ({len(out_vv)} verses) ✓')
    if all_ok:
        print('  All chapters complete ✓')

if __name__ == '__main__':
    main()
